import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { linearChannel } from "eve/channels/linear";

// Credentials come from env: LINEAR_AGENT_ACCESS_TOKEN and
// LINEAR_WEBHOOK_SECRET. See SETUP.md.
export default linearChannel();

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
});

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";

export default defineEval({
  description: "A vague ticket still gets the full structured triage output.",
  async test(t) {
    await t.send(
      [
        "Triage this ticket:",
        "",
        "Title: thing looks weird",
        "Description: idk it's just off on my phone",
      ].join("\n")
    );
    t.succeeded();
    t.check(t.reply, includes(/Priority:\s*(Urgent|High|Medium|Low)/i));
    t.check(t.reply, includes(/Team:\s*(Platform|Web|Mobile|Growth)/i));
    t.check(t.reply, includes(/Missing info:/i));
  },
});

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";

export default defineEval({
  description: "A production outage is triaged Urgent for Platform.",
  async test(t) {
    await t.send(
      [
        "Triage this ticket:",
        "",
        "Title: API returning 500s for all requests since 14:20 UTC",
        "Description: Every customer API call fails. Status page is red.",
      ].join("\n")
    );
    t.succeeded();
    t.check(t.reply, includes(/Priority:\s*Urgent/i));
    t.check(t.reply, includes(/Team:\s*Platform/i));
  },
});
